parameter DEPTH = 8;
parameter DATA_W = 8;
parameter MASK_W = 2;
localparam GRAN = DATA_W / MASK_W;
logic [GRAN-1:0] mem[MASK_W][DEPTH];
always_ff @(posedge clk)
  if (wen)
    for (int i = 0; i < MASK_W; i++)
      if (mask[i])
        mem[i][addr] <= wdata[i*GRAN +: GRAN];

parameter DATA_W = 16;
parameter MASK_W = 4;
localparam GRAN = DATA_W / MASK_W;
logic [DATA_W-1:0] wdata;
logic [MASK_W-1:0] mask;
logic [GRAN-1:0] slice [MASK_W];
generate
  for (genvar i = 0; i < MASK_W; i++)
    assign slice[i] = wdata[i*GRAN +: GRAN];
endgenerate

parameter DEPTH = 8;
parameter DATA_W = 8;
parameter MASK_W = 2;
localparam GRAN = DATA_W / MASK_W;
logic [GRAN-1:0] mem[MASK_W][DEPTH];
logic [DATA_W-1:0] rdata;
logic [$clog2(DEPTH)-1:0] raddr;
always_comb begin
  rdata = '0;
  for (int i = 0; i < MASK_W; i++)
    rdata[i*GRAN +: GRAN] = mem[i][raddr];
end
